import React, { useEffect, useState } from 'react';
import styles from './SuccessOverlay.module.css';

export function SuccessOverlay({ show, onReset }) {
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    if (show) {
      requestAnimationFrame(() => setVisible(true));
    } else {
      setVisible(false);
    }
  }, [show]);

  if (!show) return null;

  return (
    <div className={`${styles.overlay} ${visible ? styles.in : ''}`}>
      <div className={styles.card}>
        <div className={styles.iconWrap}>
          <svg width="40" height="40" viewBox="0 0 40 40" fill="none">
            <circle cx="20" cy="20" r="20" fill="var(--color-success)" />
            <path d="M11 20.5L17 26.5L29 14" stroke="white" strokeWidth="2.5"
              strokeLinecap="round" strokeLinejoin="round"
              className={styles.checkPath}
            />
          </svg>
        </div>
        <h2 className={styles.title}>Access Granted</h2>
        <p className={styles.sub}>Welcome to the 1B MVP Dream</p>
        <button className={styles.btn} onClick={onReset} type="button">
          Lock Again
        </button>
      </div>
    </div>
  );
}
